import React, { useState } from 'react';
import { FaHeart, FaTimes, FaCrown, FaUser, FaComments, FaBell, FaSearch, FaMapMarkerAlt } from 'react-icons/fa';
import { BiLogOut } from 'react-icons/bi';
import LanguageSwitcher from './LanguageSwitcher';
import { generateMockUsers } from '../utils/images';

function Swipe({ 
  user, 
  onProfile, 
  onChat, 
  onFilter, 
  onNotifications, 
  onLogout, 
  onSubscribe, 
  isSubscribed,
  onNearby 
}) {
  const [messagesLeft, setMessagesLeft] = useState(3);
  const [users] = useState(generateMockUsers(10));
  const [index, setIndex] = useState(0);

  const totalMessages = messagesLeft + (user?.extraMessages || 0);
  const currentUser = users[index];

  const next = () => setIndex((i) => (i + 1) % users.length);

  const handleLike = () => {
    if (totalMessages <= 0 && !isSubscribed) {
      return alert('💎 Abonnez-vous ou ajoutez des photos pour plus de messages');
    }
    if (user?.extraMessages > 0) {
      const updatedUser = {
        ...user,
        extraMessages: user.extraMessages - 1
      };
      if (onProfile) onProfile(updatedUser);
    } else {
      setMessagesLeft((m) => m - 1);
    }
    alert(`❤️ Vous avez aimé ${currentUser.name}`);
    next();
  };

  const handleDislike = () => {
    alert(`👎 Vous avez passé ${currentUser.name}`);
    next();
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <FaHeart style={styles.logoIcon} />
          <h1 style={styles.title}>Chatalgerie</h1>
          <LanguageSwitcher />
        </div>
        <div style={styles.headerRight}>
          <button onClick={onNearby} style={styles.iconBtn} title="Utilisateurs proches"><FaMapMarkerAlt /></button>
          <button onClick={onFilter} style={styles.iconBtn} title="Filtrer"><FaSearch /></button>
          <button onClick={onNotifications} style={styles.iconBtn} title="Notifications"><FaBell /></button>
          <button onClick={onChat} style={styles.iconBtn} title="Chat"><FaComments /></button>
          <button onClick={onProfile} style={styles.iconBtn} title="Profil"><FaUser /></button>
          <button onClick={onLogout} style={styles.iconBtn} title="Déconnexion"><BiLogOut /></button>
        </div>
      </div>

      <div style={styles.card}>
        <div style={styles.imageContainer}>
          <img src={currentUser.image} alt={currentUser.name} style={styles.userImage} />
          {isSubscribed && (
            <div style={styles.premiumBadge}>
              <FaCrown style={styles.crownIcon} /> Premium
            </div>
          )}
        </div>
        <div style={styles.userInfo}>
          <h2 style={styles.userName}>{currentUser.name}, <span style={styles.userAge}>{currentUser.age}</span></h2>
          <p style={styles.userCity}>📍 {currentUser.city}</p>
          <p style={styles.userBio}>{currentUser.bio}</p>
        </div>

        <div style={styles.messagesInfo}>
          <p style={styles.messagesText}>
            💬 {totalMessages} messages restants
            {user?.extraMessages > 0 && (
              <span style={styles.bonusBadge}> +{user.extraMessages} bonus</span>
            )}
          </p>
          {user?.imageCount > 0 && (
            <p style={styles.photoBadge}>📸 {user.imageCount} photos • {user.imageCount * 5} messages bonus</p>
          )}
        </div>

        <div style={styles.actions}>
          <button onClick={handleDislike} style={styles.dislikeBtn}><FaTimes /></button>
          <button onClick={handleLike} style={styles.likeBtn}><FaHeart /></button>
        </div>

        {!isSubscribed && (
          <button onClick={onSubscribe} style={styles.premiumBtn}>
            <FaCrown style={{ marginRight: '8px' }} /> Devenir Premium
          </button>
        )}
        
        {user?.imageCount < 10 && (
          <p style={styles.addPhotoHint} onClick={onProfile}>
            📸 Ajoutez des photos pour +5 messages chacune ({user?.imageCount || 0}/10)
          </p>
        )}
      </div>
    </div>
  );
}

const styles = {
  container: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #FFB6C1, #87CEEB)',
    padding: '20px',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  header: {
    width: '100%',
    maxWidth: '500px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '15px',
    padding: '10px 15px',
    backgroundColor: 'rgba(255,255,255,0.9)',
    borderRadius: '20px',
    boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
    flexWrap: 'wrap',
    gap: '8px',
  },
  logoIcon: {
    fontSize: '1.8rem',
    color: '#FF1493',
  },
  headerRight: {
    display: 'flex',
    gap: '6px',
    flexWrap: 'wrap',
    alignItems: 'center',
  },
  iconBtn: {
    background: 'rgba(255,255,255,0.9)',
    border: 'none',
    borderRadius: '50%',
    width: '38px',
    height: '38px',
    fontSize: '0.9rem',
    cursor: 'pointer',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    color: '#555',
    transition: 'all 0.3s',
    boxShadow: '0 2px 8px rgba(0,0,0,0.06)',
  },
  title: {
    background: 'linear-gradient(45deg, #FF69B4, #4A90D9)',
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
    fontSize: '1.4rem',
    margin: 0,
    fontWeight: 'bold',
  },
  card: {
    backgroundColor: 'white',
    padding: '25px',
    borderRadius: '28px',
    maxWidth: '420px',
    width: '100%',
    textAlign: 'center',
    boxShadow: '0 20px 60px rgba(0,0,0,0.12)',
  },
  imageContainer: {
    position: 'relative',
    width: '100%',
    height: '280px',
    borderRadius: '20px',
    overflow: 'hidden',
    marginBottom: '15px',
    backgroundColor: '#f0f0f0',
  },
  userImage: {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
  },
  premiumBadge: {
    position: 'absolute',
    top: '12px',
    right: '12px',
    background: 'linear-gradient(45deg, #FFD700, #FFA500)',
    padding: '6px 14px',
    borderRadius: '20px',
    color: 'white',
    fontSize: '0.75rem',
    fontWeight: 'bold',
    display: 'flex',
    alignItems: 'center',
    gap: '5px',
    boxShadow: '0 4px 15px rgba(255,215,0,0.4)',
  },
  crownIcon: {
    fontSize: '0.9rem',
  },
  userInfo: {
    marginBottom: '15px',
  },
  userName: {
    fontSize: '1.6rem',
